local Pet = {}

function Pet.new(name, species)
	local self = {
		name = name,
		species = species,
		hunger = 0,
	}

	setmetatable(self, Pet)

	return self
end

function Pet:feed(amount)
	self.hunger = self.hunger - amount
	if self.hunger < 0 then
		self.hunger = 0
	end
end

function Pet.__tostring(self)
	return self.name .. " the " .. self.species
end

